#include "interface.h"
#include <cstdint>
#include <vector>

uint64_t blend_checksum(
    const std::vector<uint8_t>& src,
    const std::vector<uint8_t>& dst,
    int width,
    int height,
    int iters) {
    (void)width;
    (void)height;
    if (iters <= 0) return 0;

    const std::size_t n = src.size();
    const uint8_t* s = src.data();
    const uint8_t* d = dst.data();

    uint64_t hash = 1469598103934665603ULL;
    const uint64_t prime = 1099511628211ULL;

    for (std::size_t i = 0; i < n; i += 4) {
        const uint32_t a = s[i + 3];
        const uint32_t inv_a = 255u - a;

        uint32_t r = s[i] * a + d[i] * inv_a;
        hash ^= (r + 127u) / 255u;
        hash *= prime;

        uint32_t g = s[i + 1] * a + d[i + 1] * inv_a;
        hash ^= (g + 127u) / 255u;
        hash *= prime;

        uint32_t b = s[i + 2] * a + d[i + 2] * inv_a;
        hash ^= (b + 127u) / 255u;
        hash *= prime;

        hash ^= 255u;
        hash *= prime;
    }

    return hash;
}
